import{_ as t,o,c as r,ag as i}from"./chunks/framework.CVaJrGn7.js";const g=JSON.parse('{"title":"Introduction","description":"Introduction to GuideFlow.js — an open-source, AI-powered product tour library for React, Vue, Svelte and Vanilla JS. Learn why GuideFlow beats Driver.js and Intro.js.","frontmatter":{"description":"Introduction to GuideFlow.js — an open-source, AI-powered product tour library for React, Vue, Svelte and Vanilla JS. Learn why GuideFlow beats Driver.js and Intro.js.","keywords":"GuideFlow introduction, product tour library overview, user onboarding JavaScript, open source tour library","head":[["link",{"rel":"canonical","href":"https://realnerdzw.github.io/GuideFlow/guide/"}],["meta",{"property":"og:url","content":"https://realnerdzw.github.io/GuideFlow/guide/"}],["meta",{"property":"og:title","content":"Introduction — GuideFlow.js"}],["meta",{"property":"og:description","content":"Introduction to GuideFlow.js — an open-source, AI-powered product tour library for React, Vue, Svelte and Vanilla JS. Learn why GuideFlow beats Driver.js and Intro.js."}],["meta",{"name":"twitter:title","content":"Introduction — GuideFlow.js"}],["meta",{"name":"twitter:description","content":"Introduction to GuideFlow.js — an open-source, AI-powered product tour library for React, Vue, Svelte and Vanilla JS. Learn why GuideFlow beats Driver.js and Intro.js."}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"BreadcrumbList\\",\\"itemListElement\\":[{\\"@type\\":\\"ListItem\\",\\"position\\":1,\\"name\\":\\"Home\\",\\"item\\":\\"https://realnerdzw.github.io/GuideFlow/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":2,\\"name\\":\\"Guide\\",\\"item\\":\\"https://realnerdzw.github.io/GuideFlow/guide/\\"}]}"]]},"headers":[],"relativePath":"guide/index.md","filePath":"guide/index.md","lastUpdated":1775565534000}'),n={name:"guide/index.md"};function a(d,e,s,l,c,u){return o(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>GuideFlow.js is an open-source, AI-powered product tour library that helps you guide users through your application with context-aware, personalised onboarding experiences.</p><h2 id="why-guideflow" tabindex="-1">Why GuideFlow? <a class="header-anchor" href="#why-guideflow" aria-label="Permalink to &quot;Why GuideFlow?&quot;">​</a></h2><p>Most tour libraries treat onboarding as a static linear script. GuideFlow treats it as a conversation:</p><ul><li><strong>AI-generated steps</strong> — point GuideFlow at any page and it will write the tour for you</li><li><strong>Intent detection</strong> — watch how users interact and surface the right tour at the right moment</li><li><strong>Adaptive flows</strong> — skip steps the user already understands, branch based on their role or data</li><li><strong>Analytics built-in</strong> — track completion rates, drop-offs, and run A/B experiments without extra SDKs</li><li><strong>DevTools extension</strong> — build tours visually, inspect state, and push flows straight from your browser</li></ul><h2 id="packages" tabindex="-1">Packages <a class="header-anchor" href="#packages" aria-label="Permalink to &quot;Packages&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Package</th><th>Description</th></tr></thead><tbody><tr><td><code>@guideflow/core</code></td><td>Framework-agnostic engine, zero dependencies</td></tr><tr><td><code>@guideflow/react</code></td><td>React 17/18/19 hooks and components</td></tr><tr><td><code>@guideflow/vue</code></td><td>Vue 3 composables and plugin</td></tr><tr><td><code>@guideflow/svelte</code></td><td>Svelte 4/5 stores</td></tr><tr><td><code>@guideflow/ai</code></td><td>AI brain — OpenAI, Anthropic, Ollama, Mock</td></tr><tr><td><code>@guideflow/analytics</code></td><td>Event collection, transports, A/B testing</td></tr><tr><td><code>@guideflow/cli</code></td><td><code>guideflow init / studio / export / push</code></td></tr><tr><td><code>@guideflow/devtools</code></td><td>Manifest V3 browser extension</td></tr></tbody></table><h2 id="design-principles" tabindex="-1">Design Principles <a class="header-anchor" href="#design-principles" aria-label="Permalink to &quot;Design Principles&quot;">​</a></h2><ol><li><strong>Zero dependencies in core</strong> — <code>@guideflow/core</code> ships with no runtime dependencies</li><li><strong>SSR safe</strong> — every DOM access is guarded; works in Next.js App Router, Nuxt, and SvelteKit</li><li><strong>CSP compliant</strong> — all style injection accepts a <code>nonce</code> parameter</li><li><strong>Tree-shakeable</strong> — ESM-first; only import what you use</li><li><strong>Type-safe</strong> — written in strict TypeScript; full generics support for your flow context</li></ol>',9)])])}const h=t(n,[["render",a]]);export{g as __pageData,h as default};
